262→    public void maybeWaitForNonEmptyTopology(final Supplier<StreamThread.State> threadState) {
263→        if (isEmpty() && threadState.get().isAlive()) {
264→            try {
265→                lock();
266→                while (isEmpty() && threadState.get().isAlive()) {
267→                    try {
268→                        log.debug("Detected that the topology is currently empty, waiting for something to process");
269→                        version.topologyCV.await();
270→                    } catch (final InterruptedException e) {
271→                        log.error("StreamThread was interrupted while waiting on empty topology", e);
272→                    }
273→                }
274→            } finally {
275→                unlock();
276→            }
277→        }
278→    }
