280→    /**
281→     * Adds the topology and registers a future that listens for all threads on the older version to see the update
282→     */
283→    public void registerAndBuildNewTopology(final KafkaFutureImpl<Void> future, final InternalTopologyBuilder newTopologyBuilder) {
284→        try {
285→            lock();
286→            buildAndVerifyTopology(newTopologyBuilder);
287→            log.info("New NamedTopology {} passed validation and will be added, old topology version is {}", newTopologyBuilder.topologyName(), version.topologyVersion.get());
288→            version.topologyVersion.incrementAndGet();
289→            version.activeTopologyUpdateListeners.add(new TopologyVersionListener(topologyVersion(), future));
290→            builders.put(newTopologyBuilder.topologyName(), newTopologyBuilder);
291→            wakeupThreads();
292→            notifyLifecycleObservers();
293→            log.info("Added NamedTopology {} and updated topology version to {}", newTopologyBuilder.topologyName(), version.topologyVersion.get());
294→        } catch (final Throwable throwable) {
295→            log.error("Failed to add NamedTopology {}, please retry the operation.", newTopologyBuilder.topologyName());
296→            future.completeExceptionally(throwable);
297→        } finally {
298→            unlock();
299→        }
300→    }
