330→    public KafkaFuture<Void> unregisterTopology(final KafkaFutureImpl<Void> removeTopologyFuture,
331→                                                final String topologyName) {
332→        try {
333→            lock();
334→            log.info("Beginning removal of NamedTopology {}, old topology version is {}", topologyName, version.topologyVersion.get());
335→            version.topologyVersion.incrementAndGet();
336→            version.activeTopologyUpdateListeners.add(new TopologyVersionListener(topologyVersion(), removeTopologyFuture));
337→            final InternalTopologyBuilder removedBuilder = builders.remove(topologyName);
338→            removedBuilder.fullSourceTopicNames().forEach(allInputTopics::remove);
339→            removedBuilder.allSourcePatternStrings().forEach(allInputTopics::remove);
340→            notifyLifecycleObservers();
341→            log.info("Finished removing NamedTopology {}, topology version was updated to {}", topologyName, version.topologyVersion.get());
342→        } catch (final Throwable throwable) {
343→            log.error("Failed to remove NamedTopology {}, please retry.", topologyName);
344→            removeTopologyFuture.completeExceptionally(throwable);
345→        } finally {
346→            unlock();
347→        }
348→        return removeTopologyFuture;
349→    }
