360→    private void buildAndVerifyTopology(final InternalTopologyBuilder builder) {
361→        builder.rewriteTopology(config);
362→        builder.buildTopology();
363→
364→        final Set<String> allInputTopicsCopy = new HashSet<>(allInputTopics);
365→
366→        // As we go, check each topology for overlap in the set of input topics/patterns
367→        final int numInputTopics = allInputTopicsCopy.size();
368→        final List<String> inputTopics = builder.fullSourceTopicNames();
369→        final Collection<String> inputPatterns = builder.allSourcePatternStrings();
370→
371→        final Set<String> newInputTopics = new HashSet<>(inputTopics);
372→        newInputTopics.addAll(inputPatterns);
373→
374→        final int numNewInputTopics = newInputTopics.size();
375→        allInputTopicsCopy.addAll(newInputTopics);
376→
377→        if (allInputTopicsCopy.size() != numInputTopics + numNewInputTopics) {
378→            inputTopics.retainAll(allInputTopicsCopy);
379→            inputPatterns.retainAll(allInputTopicsCopy);
380→            log.error("Tried to add the NamedTopology {} but it had overlap with other input topics {} or patterns {}",
381→                      builder.topologyName(), inputTopics, inputPatterns);
382→            throw new TopologyException("Named Topologies may not subscribe to the same input topics or patterns");
383→        }
384→
385→        final ProcessorTopology globalTopology = builder.buildGlobalStateTopology();
386→        if (globalTopology != null) {
387→            if (builder.topologyName() != null) {
388→                throw new IllegalStateException("Global state stores are not supported with Named Topologies");
389→            } else if (this.globalTopology != null) {
390→                throw new TopologyException("Topology builder had global state, but global topology has already been set");
391→            } else {
392→                this.globalTopology = globalTopology;
393→                globalStateStores.putAll(builder.globalStateStores());
394→            }
395→        }
396→        allInputTopics.addAll(newInputTopics);
397→    }
