399→    public int numStreamThreads(final StreamsConfig config) {
400→        final int configuredNumStreamThreads = config.getInt(StreamsConfig.NUM_STREAM_THREADS_CONFIG);
401→
402→        // If there are named topologies but some are empty, this indicates a bug in user code
403→        if (hasNamedTopologies()) {
404→            if (hasNoLocalTopology()) {
405→                log.error("Detected a named topology with no input topics, a named topology may not be empty.");
406→                throw new TopologyException("Topology has no stream threads and no global threads, " +
407→                                                "must subscribe to at least one source topic or pattern.");
408→            }
409→        } else {
410→            // If both the global and non-global topologies are empty, this indicates a bug in user code
411→            if (hasNoLocalTopology() && !hasGlobalTopology()) {
412→                log.error("Topology with no input topics will create no stream threads and no global thread.");
413→                throw new TopologyException("Topology has no stream threads and no global threads, " +
414→                                                "must subscribe to at least one source topic or global table.");
415→            }
416→        }
417→
418→        // Lastly we check for an empty non-global topology and override the threads to zero if set otherwise
419→        if (configuredNumStreamThreads != 0 && hasNoLocalTopology()) {
420→            log.info("Overriding number of StreamThreads to zero for global-only topology");
421→            return 0;
422→        }
423→
424→        return configuredNumStreamThreads;
425→    }
