689→    public static class Subtopology implements Comparable<Subtopology> {
690→        final int nodeGroupId;
691→        final String namedTopology;
692→
693→        public Subtopology(final int nodeGroupId, final String namedTopology) {
694→            this.nodeGroupId = nodeGroupId;
695→            this.namedTopology = namedTopology;
696→        }
697→
698→        @Override
699→        public boolean equals(final Object o) {
700→            if (this == o) {
701→                return true;
702→            }
703→            if (o == null || getClass() != o.getClass()) {
704→                return false;
705→            }
706→            final Subtopology that = (Subtopology) o;
707→            return nodeGroupId == that.nodeGroupId &&
708→                    Objects.equals(namedTopology, that.namedTopology);
709→        }
710→
711→        @Override
712→        public int hashCode() {
713→            return Objects.hash(nodeGroupId, namedTopology);
714→        }
715→
716→        @Override
717→        public int compareTo(final Subtopology other) {
718→            if (nodeGroupId != other.nodeGroupId) {
719→                return Integer.compare(nodeGroupId, other.nodeGroupId);
720→            }
721→            if (namedTopology == null) {
722→                return other.namedTopology == null ? 0 : -1;
723→            }
724→            if (other.namedTopology == null) {
725→                return 1;
726→            }
727→
728→            // Both not null
729→            return namedTopology.compareTo(other.namedTopology);
730→        }
731→    }
732→}
